import { applyDecorators, UseGuards } from '@nestjs/common';
import { ApiUnauthorizedResponse } from '@nestjs/swagger';

import { Role } from '@modules/user/entities';

import { JwtAuthGuard, RoleGuard } from '@observables/guards';

import { Roles } from '@utils/decorators';

export function Auth(...roles: Role[]) {
  return applyDecorators(
    Roles(...roles),
    UseGuards(JwtAuthGuard, RoleGuard),
    ApiUnauthorizedResponse({ description: 'Unauthorized' }),
  );
}

import {
  Body,
  Controller,
  Delete,
  Get,
  Param,
  Patch,
  Post,
  Query,
  UseGuards,
} from '@nestjs/common';
import { ApiBearerAuth, ApiResponse, ApiTags } from '@nestjs/swagger';

import { BankAccountService } from '@bank-account/bank-account.service';
import { BankAccountDto, BankAccountNameDto, BankAccountQueryParams, CreateBankAccountDto, UpdateBankAccountDto, VerifyBankAccountDto } from '@bank-account/dto';

import { ADLogger } from '@infra/logger';

import { Company } from '@modules/company/entities';

import { ApiKeyCompanyGuard } from '@observables/guards/api-key';

import { BaseResult } from '@utils/base.result';
import { BaseResultPagination } from '@utils/base.result.pagination';
import { CompanyLogin } from '@utils/decorators';
import { PaginationDto } from '@utils/pagination.dto';

@ApiTags('Api Tài khoản ngân hàng sử dụng api key')
@ApiBearerAuth('APIKEY')
@UseGuards(ApiKeyCompanyGuard)
@Controller('bank-account-api-key')
export class BankAccountApiKeyController {
  private readonly logger = new ADLogger(BankAccountApiKeyController.name);
  constructor(
    private readonly bankAccountService: BankAccountService,
  ) { }

  @Post()
  @ApiResponse({ type: BaseResult<BankAccountDto> })
  async create(
    @CompanyLogin() company: Company,
    @Body() createBankAccountDto: CreateBankAccountDto) {
    this.logger.log(`${company.getInfo()} :: start create :: createBankAccountDto`, createBankAccountDto);
    const item = await this.bankAccountService.create(company, createBankAccountDto);
    this.logger.log(`${company.getInfo()} :: end create:: response`, item);
    return new BaseResult<BankAccountDto>(new BankAccountDto(item));
  }

  @Get()
  @ApiResponse({ type: BaseResultPagination<BankAccountDto> })
  async find(@Query() query: BankAccountQueryParams) {
    const [items, count] = await this.bankAccountService.find(query);
    const rs = new BaseResultPagination<BankAccountDto>();
    rs.data = new PaginationDto<BankAccountDto>(items.map(e => new BankAccountDto(e)), count, query.size, query.page);
    return rs;
  }

  @Get('bank-holder')
  @ApiResponse({ type: String })
  getBankHolderName(@Query() query: BankAccountNameDto) {
    return this.bankAccountService.getBankHolderName(query);
  }

  @Patch(':id')
  @ApiResponse({ type: BaseResult })
  async update(
    @CompanyLogin() company: Company,
    @Param('id') id: number,
    @Body() updateBankAccountDto: UpdateBankAccountDto,
  ) {
    this.logger.log(`${company.getInfo()} :: start update :: update`, { id, updateBankAccountDto });
    await this.bankAccountService.update(+id, updateBankAccountDto, company);
    this.logger.log(`${company.getInfo()} :: end update :: response OK`);
    return new BaseResult();
  }

  @Delete(':id')
  @ApiResponse({ type: BaseResult })
  async remove(
    @CompanyLogin() company: Company,
    @Param('id') id: number) {
    this.logger.log(`${company.getInfo()} :: start remove :: id`, { id });
    await this.bankAccountService.remove(+id, company);
    this.logger.log(`${company.getInfo()} :: end remove :: response OK`);
    return new BaseResult();
  }

  @Post(':id/resend-otp')
  @ApiResponse({ type: BaseResult })
  async resendOTP(
    @CompanyLogin() company: Company,
    @Param('id') id: number) {
    this.logger.log(`${company.getInfo()} :: start resendOTP :: id`, { id });
    await this.bankAccountService.resendOtp(company, +id);
    this.logger.log(`${company.getInfo()} :: end resendOTP :: response OK`);
    return new BaseResult();
  }

  @Post(':id/verify-otp')
  @ApiResponse({ type: BaseResult })
  async verifyOTP(
    @CompanyLogin() company: Company,
    @Param('id') id: number,
    @Body() body: VerifyBankAccountDto,
  ) {
    this.logger.log(`${company.getInfo()} :: start verifyOTP:: id`, { id, body });
    await this.bankAccountService.verifyOtp(company, +id, body.otp);
    this.logger.log(`${company.getInfo()} :: end verifyOTP :: response OK`);
    return new BaseResult();
  }
}

import {
  Body,
  Controller,
  Delete,
  ForbiddenException,
  Get,
  Param,
  Patch,
  Post,
  Query,
} from '@nestjs/common';
import { ApiResponse, ApiTags } from '@nestjs/swagger';

import { BankAccountService } from '@bank-account/bank-account.service';
import { BankAccountDto, BankAccountQueryParams, CreateBankAccountDto, UpdateBankAccountDto, VerifyBankAccountDto } from '@bank-account/dto';

import { Role, User } from '@modules/user/entities';

import { BaseResult } from '@utils/base.result';
import { BaseResultPagination } from '@utils/base.result.pagination';
import { Admin, Auth, Created, Login, UserLogin } from '@utils/decorators';
import { PaginationDto } from '@utils/pagination.dto';

@ApiTags('Api Tài khoản ngân hàng')
@Controller('bank-account')
@Login()
export class BankAccountController {
  constructor(private readonly bankAccountService: BankAccountService) { }

  @Post()
  @Auth(Role.User)
  @Created()
  async create(@UserLogin() user: User, @Body() createBankAccountDto: CreateBankAccountDto) {
    const item = await this.bankAccountService.create(user.company, createBankAccountDto, user);
    return new BaseResult<BankAccountDto>(new BankAccountDto(item));
  }

  @Get()
  @Admin()
  @ApiResponse({ type: BaseResultPagination<BankAccountDto> })
  async find(@Query() query: BankAccountQueryParams) {
    const [items, count] = await this.bankAccountService.find(query);
    const rs = new BaseResultPagination<BankAccountDto>();
    rs.data = new PaginationDto<BankAccountDto>(items.map(e => new BankAccountDto(e)), count, query.page, query.size);
    return rs;
  }

  @Get('me')
  @ApiResponse({ type: BaseResultPagination<BankAccountDto> })
  async findMe(@UserLogin() user: User, @Query() query: BankAccountQueryParams) {
    query.company = { id: user.company?.id };
    const [items, count] = await this.bankAccountService.find(query);
    const rs = new BaseResultPagination<BankAccountDto>();
    rs.data = new PaginationDto<BankAccountDto>(items.map(e => new BankAccountDto(e)), count, query.size, query.page);
    return rs;
  }
  @Get('sync-sepay')
  @Admin()
  @ApiResponse({ type: BaseResult })
  syncBankAccountFromSepay(@Query() query: {
    companyId: string,
    bankId: string
  }) {
    return this.bankAccountService.syncBankAccountFromSepay(query.companyId, query.bankId);
  }

  @Get(':id')
  @ApiResponse({ type: BankAccountDto })
  async findOne(@UserLogin() user: User, @Param('id') id: number) {
    const item = await this.bankAccountService.findOneExist(+id);
    if (item.company?.id != user.company?.id && user.role != Role.Admin) throw new ForbiddenException();
    return new BankAccountDto(item);
  }

  @Patch(':id')
  @ApiResponse({ type: BaseResult })
  async update(
    @UserLogin() user: User,
    @Param('id') id: number,
    @Body() updateBankAccountDto: UpdateBankAccountDto,
  ) {
    await this.bankAccountService.update(+id, updateBankAccountDto, user.company, user);
    return new BaseResult();
  }

  @Delete(':id')
  @ApiResponse({ type: BaseResult })
  async remove(
    @UserLogin() user: User,
    @Param('id') id: number) {
    await this.bankAccountService.remove(+id, user.company, user);
    return new BaseResult();
  }

  @Post(':id/resend-otp')
  @ApiResponse({ type: BaseResult })
  async resendOTP(
    @UserLogin() user: User,
    @Param('id') id: number) {
    await this.bankAccountService.resendOtp(user.company, +id);
    return new BaseResult();
  }

  @Post(':id/verify-otp')
  @ApiResponse({ type: BaseResult })
  async verifyOTP(
    @UserLogin() user: User,
    @Param('id') id: number,
    @Body() body: VerifyBankAccountDto,
  ) {
    await this.bankAccountService.verifyOtp(user.company, +id, body.otp);
    return new BaseResult();
  }

  @Post(':id/sync-va-name')
  @ApiResponse({ type: BaseResult })
  async syncVAName(
    @Param('id') id: number) {
    await this.bankAccountService.syncVaName(+id);
    return new BaseResult();
  }
}

