import { CanActivate, ExecutionContext, Injectable } from '@nestjs/common';

import { CompanyService } from '@modules/company';

@Injectable()
export class ApiKeyCompanyGuard implements CanActivate {
  constructor(
    private readonly companyService: CompanyService,
  ) { }
  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const { 'x-api-key': xApiKey, authorization, companyid, 'company-id': companyId } = request.headers;
    const apiKeyHeader = xApiKey || authorization;
    const companyIdHeader = companyid ?? companyId;
    if (!apiKeyHeader || !companyIdHeader) {
      return false;
    }

    const company = await this.companyService.findByExternalId(companyIdHeader);
    if (!company) {
      return false;
    }

    if (company.apiKey !== apiKeyHeader) {
      return false;
    }

    request.company = company;
    return true;
  }
}

