 3	import { Brackets, Repository } from 'typeorm';
 4	
 5	import { BankAccount } from '@bank-account/entities';
 6	
 7	import { TypeORMRepository } from '@infra/database/repository';
 8	
 9	import { BankAccountQueryParams } from './dto';
10	
11	@Injectable()
12	export class BankAccountRepository extends TypeORMRepository<BankAccount> {
13	  constructor(
14	    @InjectRepository(BankAccount)
15	    readonly repository: Repository<BankAccount>,
16	  ) {
17	    super(repository);
18	  }
19	  async findByQueryBuilder(query: BankAccountQueryParams) {
20	    const qb = this.repository.createQueryBuilder('t');
21	
22	    // relations
23	    const relations = Array.from(new Set(query.getRelations()));
24	    if (relations.length === 0) {
25	      relations.push('bank');
26	      relations.push('company');
27	    }
28	    relations.forEach((relation) => {
29	      qb.leftJoinAndSelect(`t.${relation}`, relation);
30	    });
31	
32	    // search
33	    if (query.search) {
34	      const search = `%${query.search}%`;
35	      qb.andWhere(
36	        new Brackets((qb1) => {
37	          qb1
38	            .where(`unaccent(t.bankAccountName) ILIKE unaccent(:search)`, { search })
39	            .orWhere(`t.bankAccountNo ILIKE :search`, { search });
40	        }),
41	      );
42	    }
43	
44	    if (query.company) {
45	      qb.andWhere(`t.company_id = :company`, { company: query.company.id });
46	    }
47	
48	    if (query.status) {
49	      qb.andWhere(`t.status = :status`, { status: query.status });
50	    }
51	
52	    // ordering
53	    const order = query.order();
54	    if (order) {
55	      Object.entries(order).forEach(([field, direction]) => {
56	        qb.addOrderBy(`t.${field}`, direction.toUpperCase() as 'ASC' | 'DESC');
57	      });
58	    }
59	
60	    // pagination
61	    qb.skip(query.skip()).take(query.take());
62	    // execute
63	    return qb.getManyAndCount();
64	  }
65	}

