 1	import { RedisClientType } from 'redis';
 2	
 3	import { ADLogger } from '@infra/logger';
 4	
 5	export function getRetryDelay(attempt: number, baseDelayMs: number, maxDelayMs: number) {
 6	  return Math.min(baseDelayMs * 2 ** Math.max(attempt - 1, 0), maxDelayMs);
 7	}
 8	
 9	export async function retryWithBackoff<T>({
10	  attempts,
11	  baseDelayMs,
12	  maxDelayMs,
13	  operationName,
14	  execute,
15	}: {
16	  attempts: number;
17	  baseDelayMs: number;
18	  maxDelayMs: number;
19	  operationName: string;
20	  execute: () => Promise<T>;
21	}): Promise<T> {
22	  const logger = new ADLogger(operationName);
23	  let lastError: unknown;
24	
25	  for (let attempt = 1; attempt <= attempts; attempt++) {
26	    try {
27	      return await execute();
28	    } catch (error) {
29	      lastError = error;
30	
31	      if (attempt >= attempts) {
32	        break;
33	      }
34	
35	      const retryInMs = getRetryDelay(attempt, baseDelayMs, maxDelayMs);
36	      logger.warn(
37	        `${operationName} failed on attempt ${attempt}/${attempts}, retrying in ${retryInMs}ms`,
38	        error instanceof Error ? error.message : error,
39	      );
40	      await new Promise((resolve) => setTimeout(resolve, retryInMs));
41	    }
42	  }
43	
44	  throw lastError;
45	}
46	
47	export function registerRedisClientLogging(
48	  client: RedisClientType,
49	  context: string,
50	) {
51	  const logger = new ADLogger(context);
52	
53	  client.on('connect', () => logger.log('Redis socket connected'));
54	  client.on('ready', () => logger.log('Redis client ready'));
55	  client.on('reconnecting', () => logger.warn('Redis reconnecting'));
56	  client.on('end', () => logger.warn('Redis connection ended'));
57	  client.on('error', (error) => logger.error('Redis client error', error instanceof Error ? error.stack : error));
58	}

